[LISTING ONE] &lt;a name=&#34;0170_0013&#34;&gt;/* Recursive descent parser for integer expressions which may include variables and function calls. */#include &#34;setjmp.h&#34;#include &#34;math.h&#34;#include &#34;ctype.h&#34;#include &#34;stdlib.h&#34;#include &#34;string.h&#34;#include &#34;stdio.h&#34;#define NUM_FUNC 100#define NUM_GLOBAL_VARS 100#define NUM_LOCAL_VARS 200#define ID_LEN 31#define FUNC_CALLS 31#define PROG_SIZE 10000#define FOR_NEST 31enum tok_types {DELIMITER, IDENTIFIER, NUMBER, KEYWORD, TEMP, STRING, BLOCK};enum tokens {ARG, CHAR, INT, IF, ELSE, FOR, DO, WHILE, SWITCH, RETURN, EOL, FINISHED, END};enum double_ops {LT=1, LE, GT, GE, EQ, NE};/* These are the constants used to call sntx_err() when a syntax error occurs. Add more if you like. NOTE: SYNTAX is a generic error message used when nothing else seems appropriate.*/enum error_msg {SYNTAX, UNBAL_PARENS, NO_EXP, EQUALS_EXPECTED, NOT_VAR, PARAM_ERR, SEMI_EXPECTED, UNBAL_BRACES, FUNC_UNDEF, TYPE_EXPECTED, NEST_FUNC, RET_NOCALL, PAREN_EXPECTED, WHILE_EXPECTED, QUOTE_EXPECTED, NOT_TEMP, TOO_MANY_LVARS};extern char *prog; /* current location in source code */extern char *p_buf; /* points to start of program buffer */extern jmp_buf e_buf; /* hold environment for longjmp() *//* An array of these structures will hold the info associated with global variables.*/extern struct var_type { char var_name[32]; enum variable_type var_type; int value;} global_vars[NUM_GLOBAL_VARS];/* This is the function call stack. */extern struct func_type { char func_name[32]; char *loc; /* location of function entry point in file */} func_stack[NUM_FUNC];/* Keyword table */extern struct commands { char command[20]; char tok;} table[];/* &#34;Standard library&#34; functions are declared here so they can be put into the internal function table that follows.*/int call_getche(void), call_putch(void);int call_puts(void), print(void), getnum(void);struct intern_func_type { char *f_name; /* function name */ int (* p)(); /* pointer to the function */} intern_func[] = { &#34;getche&#34;, call_getche, &#34;putch&#34;, call_putch, &#34;puts&#34;, call_puts, &#34;print&#34;, print, &#34;getnum&#34;, getnum, &#34;&#34;, 0 /* null terminate the list */};extern char token[80]; /* string representation of token */extern char token_type; /* contains type of token */extern char tok; /* internal representation of token */extern int ret_value; /* function return value */void eval_exp(int *value), eval_exp1(int *value);void eval_exp2(int *value);void eval_exp3(int *value), eval_exp4(int *value);void eval_exp5(int *value), atom(int *value);void eval_exp0(int *value);void sntx_err(int error), putback(void);void assign_var(char *var_name, int value);int isdelim(char c), look_up(char *s), iswhite(char c);int find_var(char *s), get_token(void);int internal_func(char *s);int is_var(char *s);char *find_func(char *name);void call(void);/* Entry point into parser. */void eval_exp(int *value){ get_token(); if(!*token) { sntx_err(NO_EXP); return; } if(*token==&#39;;&#39;) { *value = 0; /* empty expression */ return; } eval_exp0(value); putback(); /* return last token read to input stream */}/* Process an assignment expression */void eval_exp0(int *value){ char temp[ID_LEN]; /* holds name of var receiving the assignment */ register int temp_tok; if(token_type==IDENTIFIER) { if(is_var(token)) { /* if a var, see if assignment */ strcpy(temp, token); temp_tok = token_type; get_token(); if(*token==&#39;=&#39;) { /* is an assignment */ get_token(); eval_exp0(value); /* get value to assign */ assign_var(temp, *value); /* assign the value */ return; } else { /* not an assignment */ putback(); /* restore original token */ strcpy(token, temp); token_type = temp_tok; } } } eval_exp1(value);}/* This array is used by eval_exp1(). Because some compilers cannot initialize an array within a function it is defined as a global variable.*/char relops[7] = { LT, LE, GT, GE, EQ, NE, 0};/* Process relational operators. */void eval_exp1(int *value){ int partial_value; register char op; eval_exp2(value); op = *token; if(strchr(relops, op)) { get_token(); eval_exp2(&amp;partial_value); switch(op) { /* perform the relational operation */ case LT: *value = *value &lt; partial_value; break; case LE: *value = *value &lt;= partial_value; break; case GT: *value = *value &gt; partial_value; break; case GE: *value = *value &gt;= partial_value; break; case EQ: *value = *value == partial_value; break; case NE: *value = *value != partial_value; break; } }}/* Add or subtract two terms. */void eval_exp2(int *value){ register char op; int partial_value; eval_exp3(value); while((op = *token) == &#39;+&#39; || op == &#39;-&#39;) { get_token(); eval_exp3(&amp;partial_value); switch(op) { /* add or subtract */ case &#39;-&#39;: *value = *value - partial_value; break; case &#39;+&#39;: *value = *value + partial_value; break; } }}/* Multiply or divide two factors. */void eval_exp3(int *value){ register char op; int partial_value, t; eval_exp4(value); while((op = *token) == &#39;*&#39; || op == &#39;/&#39; || op == &#39;%&#39;) { get_token(); eval_exp4(&amp;partial_value); switch(op) { /* mul, div, or modulus */ case &#39;*&#39;: *value = *value * partial_value; break; case &#39;/&#39;: *value = (*value) / partial_value; break; case &#39;%&#39;: t = (*value) / partial_value; *value = *value-(t * partial_value); break; } }}/* Is a unary + or -. */void eval_exp4(int *value){ register char op; op = &#39;\0&#39;; if(*token==&#39;+&#39; || *token==&#39;-&#39;) { op = *token; get_token(); } eval_exp5(value); if(op) if(op==&#39;-&#39;) *value = -(*value);}/* Process parenthesized expression. */void eval_exp5(int *value){ if((*token == &#39;(&#39;)) { get_token(); eval_exp0(value); /* get subexpression */ if(*token != &#39;)&#39;) sntx_err(PAREN_EXPECTED); get_token(); } else atom(value);}/* Find value of number, variable or function. */void atom(int *value){ int i; switch(token_type) { case IDENTIFIER: i = internal_func(token); if(i!= -1) { /* call &#34;standard library&#34; function */ *value = (*intern_func[i].p)(); } else if(find_func(token)){ /* call user-defined function */ call(); *value = ret_value; } else *value = find_var(token); /* get var&#39;s value */ get_token(); return; case NUMBER: /* is numeric constant */ *value = atoi(token); get_token(); return; case DELIMITER: /* see if character constant */ if(*token==&#39;\&#39;&#39;) { *value = *prog; prog++; if(*prog!=&#39;\&#39;&#39;) sntx_err(QUOTE_EXPECTED); prog++; get_token(); } return; default: if(*token==&#39;)&#39;) return; /* process empty expression */ else sntx_err(SYNTAX); /* syntax error */ }}/* Display an error message. */void sntx_err(int error){ char *p, *temp; int linecount = 0; register int i; static char *e[]= { &#34;syntax error&#34;, &#34;unbalanced parentheses&#34;, &#34;no expression present&#34;, &#34;equals sign expected&#34;, &#34;not a variable&#34;, &#34;parameter error&#34;, &#34;semicolon expected&#34;, &#34;unbalanced braces&#34;, &#34;function undefined&#34;, &#34;type specifier expected&#34;, &#34;too many nested function calls&#34;, &#34;return without call&#34;, &#34;parentheses expected&#34;, &#34;while expected&#34;, &#34;closing quote expected&#34;, &#34;not a string&#34;, &#34;too many local variables&#34; }; printf(&#34;%s&#34;, e[error]); p = p_buf; while(p != prog) { /* find line number of error */ p++; if(*p == &#39;&#39;) { linecount++; } } printf(&#34; in line %d
