&#39;; i++, p--); for(i=0; i&lt;30 &amp;&amp; p&lt;=temp; i++, p++) printf(&#34;%c&#34;, *p); longjmp(e_buf, 1); /* return to save point */}/* Get a token. */get_token(void){ register char *temp; token_type = 0; tok = 0; temp = token; *temp = &#39;\0&#39;; /* skip over white space */ while(iswhite(*prog) &amp;&amp; *prog) ++prog; if(*prog==&#39;&#39;) { ++prog; ++prog; /* skip over white space */ while(iswhite(*prog) &amp;&amp; *prog) ++prog; } if(*prog==&#39;\0&#39;) { /* end of file */ *token = &#39;\0&#39;; tok = FINISHED; return(token_type=DELIMITER); } if(strchr(&#34;{}&#34;, *prog)) { /* block delimiters */ *temp = *prog; temp++; *temp = &#39;\0&#39;; prog++; return (token_type = BLOCK); } /* look for comments */ if(*prog==&#39;/&#39;) if(*(prog+1)==&#39;*&#39;) { /* is a comment */ prog += 2; do { /* find end of comment */ while(*prog!=&#39;*&#39;) prog++; prog++; } while (*prog!=&#39;/&#39;); prog++; } if(strchr(&#34;!&lt;&gt;=&#34;, *prog)) { /* is or might be a relation operator */ switch(*prog) { case &#39;=&#39;: if(*(prog+1)==&#39;=&#39;) { prog++; prog++; *temp = EQ; temp++; *temp = EQ; temp++; *temp = &#39;\0&#39;; } break; case &#39;!&#39;: if(*(prog+1)==&#39;=&#39;) { prog++; prog++; *temp = NE; temp++; *temp = NE; temp++; *temp = &#39;\0&#39;; } break; case &#39;&lt;&#39;: if(*(prog+1)==&#39;=&#39;) { prog++; prog++; *temp = LE; temp++; *temp = LE; } else { prog++; *temp = LT; } temp++; *temp = &#39;\0&#39;; break; case &#39;&gt;&#39;: if(*(prog+1)==&#39;=&#39;) { prog++; prog++; *temp = GE; temp++; *temp = GE; } else { prog++; *temp = GT; } temp++; *temp = &#39;\0&#39;; break; } if(*token) return(token_type = DELIMITER); } if(strchr(&#34;+-*^/%=;(),&#39;&#34;, *prog)){ /* delimiter */ *temp = *prog; prog++; /* advance to next position */ temp++; *temp = &#39;\0&#39;; return (token_type=DELIMITER); } if(*prog==&#39;&#34;&#39;) { /* quoted string */ prog++; while(*prog!=&#39;&#34;&#39;&amp;&amp; *prog!=&#39;&#39;) *temp++ = *prog++; if(*prog==&#39;&#39;) sntx_err(SYNTAX); prog++; *temp = &#39;\0&#39;; return(token_type=STRING); } if(isdigit(*prog)) { /* number */ while(!isdelim(*prog)) *temp++ = *prog++; *temp = &#39;\0&#39;; return(token_type = NUMBER); } if(isalpha(*prog)) { /* var or command */ while(!isdelim(*prog)) *temp++ = *prog++; token_type=TEMP; } *temp = &#39;\0&#39;; /* see if a string is a command or a variable */ if(token_type==TEMP) { tok = look_up(token); /* convert to internal rep */ if(tok) token_type = KEYWORD; /* is a keyword */ else token_type = IDENTIFIER; } return token_type;}/* Return a token to input stream. */void putback(void){ char *t; t = token; for(; *t; t++) prog--;}/* Look up a token&#39;s internal representation in the token table.*/look_up(char *s){ register int i; char *p; /* convert to lowercase */ p = s; while(*p){ *p = tolower(*p); p++; } /* see if token is in table */ for(i=0; *table[i].command; i++) if(!strcmp(table[i].command, s)) return table[i].tok; return 0; /* unknown command */}/* Return index of internal library function or -1 if not found.*/internal_func(char *s){ int i; for(i=0; intern_func[i].f_name[0]; i++) { if(!strcmp(intern_func[i].f_name, s)) return i; } return -1;}/* Return true if c is a delimiter. */isdelim(char c){ if(strchr(&#34; !;,+-&lt;&gt;&#39;/*%^=()&#34;, c) || c==9 || c==&#39;&#39; || c==0) return 1; return 0;}/* Return 1 if c is space or tab. */iswhite(char c){ if(c==&#39; &#39; || c==&#39;	&#39;) return 1; else return 0;}&lt;a name=&#34;0170_0014&#34;&gt;&lt;a name=&#34;0170_0014&#34;&gt;&lt;a name=&#34;0170_0015&#34;&gt;
 [LISTING TWO] &lt;a name=&#34;0170_0015&#34;&gt;/* A Little C interpreter. */#include &#34;stdio.h&#34;#include &#34;setjmp.h&#34;#include &#34;math.h&#34;#include &#34;ctype.h&#34;#include &#34;stdlib.h&#34;#include &#34;string.h&#34;#define NUM_FUNC 100#define NUM_GLOBAL_VARS 100#define NUM_LOCAL_VARS 200#define NUM_BLOCK 100#define ID_LEN 31#define FUNC_CALLS 31#define NUM_PARAMS 31#define PROG_SIZE 10000#define LOOP_NEST 31enum tok_types {DELIMITER, IDENTIFIER, NUMBER, KEYWORD, TEMP, STRING, BLOCK};/* add additional C keyword tokens here */enum tokens {ARG, CHAR, INT, IF, ELSE, FOR, DO, WHILE, SWITCH, RETURN, EOL, FINISHED, END};/* add additional double operators here (such as -&gt;) */enum double_ops {LT=1, LE, GT, GE, EQ, NE};/* These are the constants used to call sntx_err() when a syntax error occurs. Add more if you like. NOTE: SYNTAX is a generic error message used when nothing else seems appropriate.*/enum error_msg {SYNTAX, UNBAL_PARENS, NO_EXP, EQUALS_EXPECTED, NOT_VAR, PARAM_ERR, SEMI_EXPECTED, UNBAL_BRACES, FUNC_UNDEF, TYPE_EXPECTED, NEST_FUNC, RET_NOCALL, PAREN_EXPECTED, WHILE_EXPECTED, QUOTE_EXPECTED, NOT_TEMP, TOO_MANY_LVARS};char *prog; /* current location in source code */char *p_buf; /* points to start of program buffer */jmp_buf e_buf; /* hold environment for longjmp() *//* An array of these structures will hold the info associated with global variables.*/struct var_type { char var_name[ID_LEN]; int var_type; int value;} global_vars[NUM_GLOBAL_VARS];struct var_type local_var_stack[NUM_LOCAL_VARS];struct func_type { char func_name[ID_LEN]; char *loc; /* location of entry point in file */} func_table[NUM_FUNC];int call_stack[NUM_FUNC];struct commands { /* keyword lookup table */ char command[20]; char tok;} table[] = { /* Commands must be entered lowercase */ &#34;if&#34;, IF, /* in this table. */ &#34;else&#34;, ELSE, &#34;for&#34;, FOR, &#34;do&#34;, DO, &#34;while&#34;, WHILE, &#34;char&#34;, CHAR, &#34;int&#34;, INT, &#34;return&#34;, RETURN