&#34;); exit(1); } /* allocate memory for the program */ if((p_buf=(char *) malloc(PROG_SIZE))==NULL) { printf(&#34;allocation failure&#34;); exit(1); } /* load the program to execute */ if(!load_program(p_buf, argv[1])) exit(1); if(setjmp(e_buf)) exit(1); /* initialize long jump buffer */ /* set program pointer to start of program buffer */ prog = p_buf; prescan(); /* find the location of all functions and global variables in the program */ gvar_index = 0; /* initialize global variable index */ lvartos = 0; /* initialize local variable stack index */ functos = 0; /* initialize the CALL stack index */ /* setup call to main() */ prog = find_func(&#34;main&#34;); /* find program starting point */ prog--; /* back up to opening ( */ strcpy(token, &#34;main&#34;); call(); /* call main() to start interpreting */}/* Interpret a single statement or block of code. When interp_block() returns from it&#39;s initial call, the final brace (or a return) in main() has been encountered.*/void interp_block(void){ int value; char block = 0; do { token_type = get_token(); /* If interpreting single statement, return on first semicolon. */ /* see what kind of token is up */ if(token_type==IDENTIFIER) { /* Not a keyword, so process expression. */ putback(); /* restore token to input stream for further processing by eval_exp() */ eval_exp(&amp;value); /* process the expression */ if(*token!=&#39;;&#39;) sntx_err(SEMI_EXPECTED); } else if(token_type==BLOCK) { /* if block delimiter */ if(*token==&#39;{&#39;) /* is a block */ block = 1; /* interpreting block, not statement */ else return; /* is a }, so return */ } else /* is keyword */ switch(tok) { case CHAR: case INT: /* declare local variables */ putback(); decl_local(); break; case RETURN: /* return from function call */ func_ret(); return; case IF: /* process an if statement */ exec_if(); break; case ELSE: /* process an else statement */ find_eob(); /* find end of else block and continue execution */ break; case WHILE: /* process a while loop */ exec_while(); break; case DO: /* process a do-while loop */ exec_do(); break; case FOR: exec_for(); break; case END: exit(0); } } while (tok != FINISHED &amp;&amp; block);}/* Load a program. */load_program(char *p, char *fname){ FILE *fp; int i=0; if((fp=fopen(fname, &#34;rb&#34;))==NULL) return 0; i = 0; do { *p = getc(fp); p++; i++; } while(!feof(fp) &amp;&amp; i&lt;PROG_SIZE); *(p-2) = &#39;\0&#39;; /* null terminate the program */ fclose(fp); return 1;}/* Find the location of all functions in the program and store global variables. */void prescan(void){ char *p; char temp[32]; int brace = 0; /* When 0, this var tells us that current source position is outside of any function. */ p = prog; func_index = 0; do { while(brace) { /* bypass code inside functions */ get_token(); if(*token==&#39;{&#39;) brace++; if(*token==&#39;}&#39;) brace--; } get_token(); if(tok==CHAR || tok==INT) { /* is global var */ putback(); decl_global(); } else if(token_type==IDENTIFIER) { strcpy(temp, token); get_token(); if(*token==&#39;(&#39;) { /* must be assume a function */ func_table[func_index].loc = prog; strcpy(func_table[func_index].func_name, temp); func_index++; while(*prog!=&#39;)&#39;) prog++; prog++; /* prog points to opening curly brace of function */ } else putback(); } else if(*token==&#39;{&#39;) brace++; } while(tok!=FINISHED); prog = p;}/* Return the entry point of the specified function. Return NULL if not found.*/char *find_func(char *name){ register int i; for(i=0; i&lt;func_index; i++) if(!strcmp(name, func_table[i].func_name)) return func_table[i].loc; return NULL;}/* Declare a global variable. */void decl_global(void){ get_token(); /* get type */ global_vars[gvar_index].var_type = tok; global_vars[gvar_index].value = 0; /* init to 0 */ do { /* process comma-separated list */ get_token(); /* get name */ strcpy(global_vars[gvar_index].var_name, token); get_token(); gvar_index++; } while(*token==&#39;,&#39;); if(*token!=&#39;;&#39;) sntx_err(SEMI_EXPECTED);}/* Declare a local variable. */void decl_local(void){ struct var_type i; get_token(); /* get type */ i.var_type = tok; i.value = 0; /* init to 0 */ do { /* process comma-separated list */ get_token(); /* get var name */ strcpy(i.var_name, token); local_push(i); get_token(); } while(*token==&#39;,&#39;); if(*token!=&#39;;&#39;) sntx_err(SEMI_EXPECTED);}/* Call a function. */void call(void){ char *loc, *temp; int lvartemp; loc = find_func(token); /* find entry point of function */ if(loc==NULL) sntx_err(FUNC_UNDEF); /* function not defined */ else { lvartemp = lvartos; /* save local var stack index */ get_args(); /* get function arguments */ temp = prog; /* save return location */ func_push(lvartemp); /* save local var stack index */ prog = loc; /* reset prog to start of function */ get_params(); /* load the function&#39;s parameters with the values of the arguments */ interp_block(); /* interpret the function */ prog = temp; /* reset the program pointer */ lvartos = func_pop(); /* reset the local var stack */ }}/* Push the arguments to a function onto the local variable stack. */void get_args(void){ int value, count, temp[NUM_PARAMS]; struct var_type i; count = 0; get_token(); if(*token!=&#39;(&#39;) sntx_err(PAREN_EXPECTED); /* process a comma-separated list of values */ do { eval_exp(&amp;value); temp[count] = value; /* save temporarily */ get_token(); count++; }while(*token==&#39;,&#39;); count--; /* now, push on local_var_stack in reverse order */ for(; count&gt;=0; count--) { i.value = temp[count]; i.var_type = ARG; local_push(i); }}/* Get function parameters. */void get_params(void){ struct var_type *p; int i; i = lvartos-1; do { /* process comma-separated list of parameters */ get_token(); p = &amp;local_var_stack[i]; if(*token!=&#39;)&#39;) { if(tok!=INT &amp;&amp; tok!=CHAR) sntx_err(TYPE_EXPECTED); p-&gt;var_type = token_type; get_token()
